import React, { useState } from "react";
import EditorialFlow from "./EditorialFlow";

// ✅ onBack est maintenant optionnel (?)
interface MediaLibraryProps {
  onBack?: () => void;
}

const MediaLibrary: React.FC<MediaLibraryProps> = ({ onBack }) => {
  const [view, setView] = useState<'library' | 'flow'>('library');

  return (
    <div className="container mx-auto px-4 py-4 h-full flex flex-col">
      {/* Bouton Retour - Seulement si onBack est fourni */}
      {onBack && (
        <button
          onClick={onBack}
          className="mb-4 px-4 py-2 bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 rounded-lg text-sm transition-colors flex items-center gap-2"
        >
          <i className="fas fa-arrow-left"></i>
          Retour aux Documents
        </button>
      )}

      {/* En-tête */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow mb-4 p-4">
        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white flex items-center">
            <i className="fas fa-folder-open mr-3 text-purple-600"></i>
            Médiathèque BCM-GEST
          </h1>
          
          {/* Toggle Vue */}
          <div className="flex gap-2">
            <button
              onClick={() => setView('library')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
                view === 'library'
                  ? 'bg-purple-600 text-white shadow-lg'
                  : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600'
              }`}
            >
              <i className="fas fa-th-large"></i>
              Médiathèque
            </button>
            <button
              onClick={() => setView('flow')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
                view === 'flow'
                  ? 'bg-purple-600 text-white shadow-lg'
                  : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600'
              }`}
            >
              <i className="fas fa-project-diagram"></i>
              Flux Éditorial
            </button>
          </div>
        </div>
      </div>

      {/* Contenu */}
      {view === 'library' ? (
        <MediaLibraryGrid />
      ) : (
        <EditorialFlow />
      )}
    </div>
  );
};


// ✅ COMPOSANT GRILLE (à l'intérieur du même fichier)
const MediaLibraryGrid: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState("");
  const [typeFilter, setTypeFilter] = useState("Tous");

  const demoFiles = [
    { id: 1, name: "audio_001.mp3", type: "audio", date: "2025-01-15", size: "5.2 MB" },
    { id: 2, name: "audio_002.mp3", type: "audio", date: "2025-01-15", size: "3.8 MB" },
    { id: 3, name: "scan_chapitre1.pdf", type: "pdf", date: "2025-01-14", size: "2.1 MB" },
  ];

  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow flex-1 overflow-hidden border border-gray-200 dark:border-gray-700">
      {/* Barre de filtres */}
      <div className="bg-gray-50 dark:bg-gray-700/50 px-6 py-4 border-b border-gray-200 dark:border-gray-700">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 text-base border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-purple-500 dark:bg-gray-700 dark:text-white"
              placeholder="Rechercher un fichier..."
            />
          </div>
          <button className="px-4 py-2 bg-purple-600 hover:bg-purple-700 text-white rounded-md">
            <i className="fas fa-upload mr-2"></i> Importer
          </button>
        </div>
      </div>

      {/* Grille */}
      <div className="p-6 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {demoFiles.map((file) => (
          <div key={file.id} className="bg-white dark:bg-gray-700 rounded-lg border p-4">
            <h3 className="font-medium text-gray-900 dark:text-white">{file.name}</h3>
            <p className="text-xs text-gray-500">{file.date} • {file.size}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default MediaLibrary; // ✅ EXPORT OBLIGATOIRE
